#!/usr/bin/env python
from __future__ import annotations

import re
from pathlib import Path

from i18n_samples import _

ROOT = Path(__file__).resolve().parent
SOURCE_FILE = ROOT / "env.sample.env"
OUT_SH = ROOT / "env.sample.sh"
OUT_PS1 = ROOT / "env.sample.ps1"
OUT_BAT = ROOT / "env.sample.bat"

HEADER_ENV = """# Cross-provider canonical env sample for uag (.env style)
#
# This file is auto-updated by samples/generate_env_samples.py (interactive wizard).
# You can re-run the wizard anytime to regenerate shell-specific samples.
"""

HEADER_SH = """#!/usr/bin/env bash
# Auto-generated by samples/generate_env_samples.py (interactive wizard)
# Do not edit this file directly. Re-run the wizard to regenerate.
"""

HEADER_PS1 = """<#
 Auto-generated by samples/generate_env_samples.py (interactive wizard)
 Do not edit this file directly. Re-run the wizard to regenerate.
#>
"""

HEADER_BAT = """@echo off
REM Auto-generated by samples/generate_env_samples.py (interactive wizard)
REM Do not edit this file directly. Re-run the wizard to regenerate.
"""

