        ("UAGENT_OLLAMA_TEMPERATURE", False, "field.ollama.temperature"),
        ("UAGENT_OLLAMA_TOP_P", False, "field.ollama.top_p"),
        ("UAGENT_OLLAMA_TOP_K", False, "field.ollama.top_k"),
        ("UAGENT_OLLAMA_REPEAT_PENALTY", False, "field.ollama.repeat_penalty"),
        ("UAGENT_OLLAMA_KEEP_ALIVE", False, "field.ollama.keep_alive"),
        ("UAGENT_OLLAMA_NUM_CTX", False, "field.ollama.num_ctx"),
